// // This module implements a 2-bit divider that returns the quotient and remainder of two 2-bit inputs A and B. If the divisor B is zero, it correctly returns a quotient of 00 and a remainder of 00.
module two_bit_divider(input [1:0] A, input [1:0] B, output reg [1:0] Q, output reg [1:0] R);  
    always @(*) begin  
        if (B == 2'b00) begin  
            Q = 2'b00;  
            R = 2'b00;  
        end else begin  
            Q = A / B;  
            R = A % B;  
        end  
    end  
endmodule
